import "./App.css";
import { Routes, Route, Navigate } from "react-router-dom";
import Header from "./components/header";

// User Components
import Login from "./components/Login";
import Register from "./components/register";
import AfficherUtilisateurs from "./components/AfficherUtilisateurs";
import AjouterUtilisateur from "./components/AjouterUtilisateur";
import ModifierUtilisateur from "./components/modifierUtilisateur";

// Project Components
import Afficher from "./componentsProjects/afficher";
import Ajouter from "./componentsProjects/ajouter";
import Modifier from "./componentsProjects/modifier";
import Details from "./componentsProjects/details";

// Pages
import TaskPage from "./pages/TaskPage";
import KanbanPage from "./pages/KanbanPage";
import ReportsPage from "./pages/ReportsPage";

function ProtectedRoute({ children }) {
  const token = localStorage.getItem("token");

  if (!token) {
    return <Navigate to="/" replace />;
  }

  return children;
}

function AdminRoute({ children }) {
  const token = localStorage.getItem("token");
  const user = JSON.parse(localStorage.getItem("user"));

  if (!token) {
    return <Navigate to="/" replace />;
  }

  if (user?.role !== "admin") {
    return <Navigate to="/afficher" replace />;
  }

  return children;
}

function App() {
  return (
    <div className="App">
      <Header />
      <Routes>
        {/* Authentication */}
        <Route path="/" element={<Login />} />
        <Route path="/Register" element={<Register />} />

        {/* User Management - admin only */}
        <Route
          path="/AfficherUtilisateurs"
          element={
            <AdminRoute>
              <AfficherUtilisateurs />
            </AdminRoute>
          }
        />
        <Route
          path="/AjouterUtilisateur"
          element={
            <AdminRoute>
              <AjouterUtilisateur />
            </AdminRoute>
          }
        />
        <Route
          path="/modifierUtilisateur/:id"
          element={
            <AdminRoute>
              <ModifierUtilisateur />
            </AdminRoute>
          }
        />

        {/* Project Management - any logged user */}
        <Route
          path="/afficher"
          element={
            <ProtectedRoute>
              <Afficher />
            </ProtectedRoute>
          }
        />
        <Route
          path="/ajouter"
          element={
            <ProtectedRoute>
              <Ajouter />
            </ProtectedRoute>
          }
        />
        <Route
          path="/modifier/:id"
          element={
            <ProtectedRoute>
              <Modifier />
            </ProtectedRoute>
          }
        />
        <Route
          path="/details/:id"
          element={
            <ProtectedRoute>
              <Details />
            </ProtectedRoute>
          }
        />

        {/* Pages */}
        <Route
          path="/tasks/:id"
          element={
            <ProtectedRoute>
              <TaskPage />
            </ProtectedRoute>
          }
        />
        <Route
          path="/kanban/:id"
          element={
            <ProtectedRoute>
              <KanbanPage />
            </ProtectedRoute>
          }
        />
        <Route
          path="/reports/:id"
          element={
            <ProtectedRoute>
              <ReportsPage />
            </ProtectedRoute>
          }
        />
      </Routes>
    </div>
  );
}

export default App;
